-- Extras administrativos: dashboard, log de auditoria legível e templates
-- de treino/dieta editáveis (antes só existiam como arrays estáticos em
-- app-react/src/data/{workoutTemplates,mealTemplates}.js).

create or replace function public.admin_dashboard_stats()
returns table (
  total_users bigint,
  users_last_7d bigint,
  users_last_30d bigint,
  confirmed_users bigint,
  banned_users bigint,
  admins_count bigint,
  total_workouts bigint,
  workouts_last_7d bigint,
  total_food_logs bigint
)
language plpgsql
security definer
set search_path = public, auth
as $$
begin
  if not public.is_admin() then raise exception 'not_authorized'; end if;

  return query
    select
      (select count(*) from auth.users),
      (select count(*) from auth.users where created_at >= now() - interval '7 days'),
      (select count(*) from auth.users where created_at >= now() - interval '30 days'),
      (select count(*) from auth.users where email_confirmed_at is not null),
      (select count(*) from auth.users where banned_until is not null and banned_until > now()),
      (select count(*) from public.profiles where is_admin),
      (select count(*) from public.workouts),
      (select count(*) from public.workouts where created_at >= now() - interval '7 days'),
      (select count(*) from public.food_logs);
end;
$$;

grant execute on function public.admin_dashboard_stats() to authenticated;

create or replace function public.admin_signups_by_day(days_back int default 14)
returns table (day date, count bigint)
language plpgsql
security definer
set search_path = public, auth
as $$
begin
  if not public.is_admin() then raise exception 'not_authorized'; end if;

  return query
    select d::date, count(u.id)
    from generate_series(current_date - (days_back - 1), current_date, interval '1 day') d
    left join auth.users u on u.created_at::date = d::date
    group by d
    order by d;
end;
$$;

grant execute on function public.admin_signups_by_day(int) to authenticated;

create or replace function public.admin_list_audit_log()
returns table (
  id uuid,
  created_at timestamptz,
  admin_email text,
  target_email text,
  action text,
  details jsonb
)
language plpgsql
security definer
set search_path = public, auth
as $$
begin
  if not public.is_admin() then raise exception 'not_authorized'; end if;

  return query
    select l.id, l.created_at, a.email::text, t.email::text, l.action, l.details
    from public.admin_audit_log l
    left join auth.users a on a.id = l.admin_id
    left join auth.users t on t.id = l.target_user_id
    order by l.created_at desc
    limit 200;
end;
$$;

grant execute on function public.admin_list_audit_log() to authenticated;

-- Templates-base de treino/dieta por objetivo (meta). "days"/"meals" ficam no
-- mesmo formato que generatePlan/generateMealPlan já produzem hoje (ver
-- app-react/src/data/workoutTemplates.js e mealTemplates.js) — a lógica de
-- ajuste por IMC/nível continua em app-react, rodando sobre o que vier daqui.
create table if not exists public.workout_templates (
  meta text primary key,
  days jsonb not null,
  updated_at timestamptz not null default now()
);

alter table public.workout_templates enable row level security;

drop policy if exists "anyone can read workout_templates" on public.workout_templates;
create policy "anyone can read workout_templates" on public.workout_templates
  for select using (true);

drop policy if exists "admin full access" on public.workout_templates;
create policy "admin full access" on public.workout_templates
  for all using (public.is_admin()) with check (public.is_admin());

create table if not exists public.meal_templates (
  meta text primary key,
  meals jsonb not null,
  updated_at timestamptz not null default now()
);

alter table public.meal_templates enable row level security;

drop policy if exists "anyone can read meal_templates" on public.meal_templates;
create policy "anyone can read meal_templates" on public.meal_templates
  for select using (true);

drop policy if exists "admin full access" on public.meal_templates;
create policy "admin full access" on public.meal_templates
  for all using (public.is_admin()) with check (public.is_admin());

